class SAMLResponseValidator {
    public void validate(SAMLResponse response) throws SAMLException {
        if (response == null) {
            throw new SAMLException("SAML response is null");
        }
        
        if (response.getId() == null || response.getId().isEmpty()) {
            throw new SAMLException("Response ID is missing");
        }
        
        if (!"urn:oasis:names:tc:SAML:2.0:status:Success".equals(response.getStatus())) {
            throw new SAMLException("Response status is not Success");
        }
        
        if (response.getAssertions().isEmpty()) {
            throw new SAMLException("No assertions found in response");
        }
        
        for (SAMLAssertion assertion : response.getAssertions()) {
            validateAssertion(assertion);
        }
    }
    
    private void validateAssertion(SAMLAssertion assertion) throws SAMLException {
        if (assertion.getSubject() == null || assertion.getSubject().isEmpty()) {
            throw new SAMLException("Assertion subject is missing");
        }
        
        Instant now = Instant.now();
        
        if (assertion.getNotBefore() != null && now.isBefore(assertion.getNotBefore())) {
            throw new SAMLException("Assertion is not yet valid");
        }
        
        if (assertion.getNotOnOrAfter() != null && now.isAfter(assertion.getNotOnOrAfter())) {
            throw new SAMLException("Assertion has expired");
        }
    }
}

class SessionManager {
    private Map<String, UserSession> sessions;
    
    public SessionManager() {
        this.sessions = new HashMap<>();
    }
    
    public UserSession createSession(SAMLAssertion assertion) {
        String sessionId = UUID.randomUUID().toString();
        String userId = assertion.getSubject();
        
        String username = userId;
        List<String> usernameAttr = assertion.getAttributes().get("username");
        if (usernameAttr != null && !usernameAttr.isEmpty()) {
            username = usernameAttr.get(0);
        }
        
        Instant expiresAt = assertion.getNotOnOrAfter();
        if (expiresAt == null) {
            expiresAt = Instant.now().plusSeconds(3600);
        }
        
        UserSession session = new UserSession(
            sessionId, 
            userId, 
            username, 
            assertion.getAttributes(), 
            expiresAt
        );
        
        sessions.put(sessionId, session);
        return session;
    }
    
    public UserSession getSession(String sessionId) {
        UserSession session = sessions.get(sessionId);
        if (session != null && !session.isValid()) {
            sessions.remove(sessionId);
            return null;
        }
        return session;
    }
    
    public void invalidateSession(String sessionId) {
        sessions.remove(sessionId);
    }
    
    public void cleanupExpiredSessions() {
        sessions.entrySet().removeIf(entry -> !entry.getValue().isValid());
    }
}

